import csv

def process_csv(filename):
    data = {}
    with open(filename, 'r') as file:
        reader = csv.DictReader(file)
        for row in reader:
            if float(row['score']) >= 90:
                if 'A' not in data['a_students']:
                    data['a_students'] = [row['name']]
                else:
                    data['a_students'].append(row['name'])
            data['average_score'] = (data.get('average_score', 0) + float(row['score'])) / (data.get('count', 0) + 1)
            data['count'] += 1
    return {'average_score': round(data['average_score'], 2), 'a_students': data['a_students']}

def two_sum(nums, target):
    num_dict = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in num_dict:
            return [num_dict[complement], i]
        num_dict[num] = i
    raise ValueError("No solution found")

