use strict;
use warnings;

my $filename = shift @ARGV;

open my $fh, '<', $filename or die "Could not open $filename: $!";
my $total_lines = 0;
my $error_lines = 0;

while (my $line = <$fh>) {
    chomp $line;
    $total_lines++;
    if ($line =~ /\berror\b/i) {
        $error_lines++;
    }
}

print "$total_lines\n";
print "$error_lines\n";

close $fh;

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    public float speed = 5f;
    public float rotationSpeed = 100f;
    public float jumpForce = 10f;
    public float gravity = -9.81f;

    private Rigidbody rb;
    private Vector3 movement;
    private Vector3 mouseLookRotation;
    private bool isGrounded = false;

    void Start()
    {
        rb = GetComponent<Rigidbody>();
    }

    void Update()
    {
        movement.x = Input.GetAxis("Horizontal");
        movement.z = Input.GetAxis("Vertical");

        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector3.up * jumpForce, ForceMode.Impulse);
            isGrounded = false;
        }

        mouseLookRotation.y += Input.GetAxis("Mouse X") * rotationSpeed * Time.deltaTime;

        transform.Rotate(0, mouseLookRotation.y, 0);

        Vector3 targetPosition = transform.position + movement * speed * Time.deltaTime;
        rb.MovePosition(targetPosition);

        if (Input.GetButtonDown("Fire1"))
        {
            // Add your fire logic here
        }

        isGrounded = IsGrounded();
    }

    bool IsGrounded()
    {
        return Physics.Raycast(transform.position, -Vector3.up, 0.1f);
    }
}
